    { name: { en: 'Olive Oil', ro: 'ulei de masline', ru: 'оливковое масло', es: 'aceite de oliva' }, measure: '3 tablespoons' },
    { name: { en: 'Cucumber', ro: 'castravete', ru: 'огурец', es: 'pepino' }, measure: 'Sliced' },
    { name: { en: 'Mint', ro: 'menta', ru: 'мята', es: 'menta' }, measure: 'Leaves' },
    { name: { en: 'Peanuts', ro: 'arahide', ru: 'арахис', es: 'cacahuetes' }, measure: 'Crushed' }
